          questions: [
            { id: 'u5-s9-ex2-q1', question: '١) ﴿رَبَّنا ظَلَمْنا أَنْفُسَنا﴾', answer: '"Our Lord, we have wronged ourselves"' },
            { id: 'u5-s9-ex2-q2', question: '٢) اَللّٰهُمَّ ارْزُقْنا خالِصَ الأَعْمالِ', answer: 'O Allah, grant us sincere deeds' },
            { id: 'u5-s9-ex2-q3', question: '٣) اَللّٰهُمَّ اهْدِنا لِصالِحِ الأَخْلاقِ', answer: 'O Allah, guide us to righteous character' },
            { id: 'u5-s9-ex2-q4', question: '٤) ﴿يَاقَوْمِ اذْكُرُوا نِعْمَةَ اللهِ عَلَيْكُمْ﴾', answer: '"O my people, remember the favor of Allah upon you"' },
            { id: 'u5-s9-ex2-q5', question: '٥) ﴿يَاأَيُّهَا الَّذينَ آمَنوا توبوا إِلى اللهِ﴾', answer: '"O you who believe, repent to Allah"' },
            { id: 'u5-s9-ex2-q6', question: '٦) اَللّٰهُمَّ لا تَحْرِمْني بَرَكَةَ ما أَعْطَيْتَني', answer: 'O Allah, do not deprive me of the blessing of what You have given me' },
            { id: 'u5-s9-ex2-q7', question: '٧) اَللّٰهُمَّ اعْصِمْني فيما بَقِيَ مِنْ عُمُري', answer: 'O Allah, protect me in what remains of my life' },
            { id: 'u5-s9-ex2-q8', question: '٨) اَللّٰهُمَّ اغْفِرْ لي جَميعَ ما مَضى مِنْ ذُنوبي', answer: 'O Allah, forgive me all my past sins' },
            { id: 'u5-s9-ex2-q9', question: '٩) ﴿قُلْ يَاأَيُّهَا الكافِرونَ لَا أَعْبُدُ ما تَعْبُدونَ﴾', answer: '"Say: O disbelievers, I do not worship what you worship"' },
            { id: 'u5-s9-ex2-q10', question: '١٠) ﴿يَاأَيُّهَا النّاسُ اعْبُدوا رَبَّكُمُ الَّذي خَلَقَكُمْ﴾', answer: '"O mankind, worship your Lord who created you"' },
            { id: 'u5-s9-ex2-q11', question: '١١) اَللّٰهُمَّ لا تَحْرِمْنا خَيْرَ ما عِنْدَكَ بِشَرِّ ما عِنْدَنا', answer: 'O Allah, do not deprive us of the good that is with You because of the evil that is with us' },
            { id: 'u5-s9-ex2-q12', question: '١٢) ﴿يَاأَيُّهَا الَّذينَ آمَنوا أَطيعُوا اللهَ وَأَطيعُوا الرَّسولَ﴾', answer: '"O you who believe, obey Allah and obey the Messenger"' },
            { id: 'u5-s9-ex2-q13', question: '١٣) اَللّٰهُمَّ اجْعَلْ خَيْرَ عَمَلي آخِرَهُ وَخَيْرَ أَيّامي يَوْمَ أَلْقاكَ', answer: 'O Allah, make the best of my deeds the last of them and the best of my days the day I meet You' },
            { id: 'u5-s9-ex2-q14', question: '١٤) اَللّٰهُمَّ إِنّي أَسْأَلُكَ حُبَّكَ، وَحُبَّ مَنْ يُحِبُّكَ، وَالعَمَلَ الَّذي يُبَلِّغُني حُبَّكَ', answer: 'O Allah, I ask You for Your love, the love of those who love You, and the deeds that will bring me to Your love' },
            { id: 'u5-s9-ex2-q15', question: '١٥) ﴿يَاأَيُّهَا النّاسُ اتَّقوا رَبَّكُمُ الَّذي خَلَقَكُمْ مِنْ نَفْسٍ واحِدَةٍ وَخَلَقَ مِنْها زَوْجَها﴾', answer: '"O mankind, fear your Lord who created you from a single soul and created from it its mate"' },
            { id: 'u5-s9-ex2-q16', question: '١٦) اَللّٰهُمَّ إِنّي أَسْأَلُكَ الجَنَّةَ وَما قَرَّبَ إِلَيْها مِنْ قَوْلٍ أَوْ عَمَلٍ، وَأَعوذُ بِكَ مِنَ النّارِ وَما قَرَّبَ إِلَيْها مِنْ قَوْلٍ أَوْ عَمَلٍ', answer: 'O Allah, I ask You for Paradise and whatever brings me closer to it in word or deed, and I seek refuge in You from the Fire and whatever brings me closer to it in word or deed' },
          ],
